using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow tests ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalCases =>
    [
        (10.00m, 1, 0.0m, 10.00m),
        (10.00m, 2, 0.10m, 22.00m),
        (50.00m, 4, 0.20m, 240.00m),
        (0.01m, 1, 1.0m, 0.02m),
        (100.00m, 1, 0.0m, 100.00m),
    ];

    // --- CalculateTotal: invalid inputs ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above one")]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow tests ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount")]
    [DataRow(99.99, 50.0, 49.995, DisplayName = "50% off odd price")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountCases))]
    public void ApplyDiscount_WithDynamicData_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountCases =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (1000m, 15m, 850m),
    ];

    // --- ApplyDiscount: invalid inputs ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below zero")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_InvalidDiscount_Throws(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }
}

